export class ApiError extends Error {
    response;
    constructor(message, response) {
        super(message);
        this.response = response;
    }
}
export function toSerializable(error) {
    if (error instanceof Error) {
        return {
            name: error.name,
            message: error.message,
            stack: error.stack,
        };
    }
    return {
        name: "Unknown error",
        message: String(error),
    };
}
