import { browser } from "$app/environment";
import { ApiError } from "./types";
import { InjectionToken } from "@gitbutler/core/context";
import { derived, get } from "svelte/store";
export const HTTP_CLIENT = new InjectionToken("HttpClient");
export const DEFAULT_HEADERS = {
    "Content-Type": "application/json",
};
export class HttpClient {
    fetch;
    token;
    credentials;
    apiUrl;
    /**
     * Signals whether authentication is available.
     *
     * It should be noted that the authentication may be present but invalid.
     */
    authenticationAvailable;
    constructor(fetch = window.fetch, publicApiBaseUrl, token, credentials = "same-origin") {
        this.fetch = fetch;
        this.token = token;
        this.credentials = credentials;
        this.apiUrl = new URL("/api/", publicApiBaseUrl);
        this.authenticationAvailable = derived(token, (token) => !!token);
    }
    getApiUrl(path) {
        return new URL(path, this.apiUrl);
    }
    async request(path, opts) {
        if (!browser) {
            throw new Error("Can't call fetch in SSR phase");
        }
        const butlerHeaders = new Headers(DEFAULT_HEADERS);
        const token = get(this.token);
        if (token)
            butlerHeaders.set("X-Auth-Token", token);
        if (opts.headers) {
            Object.entries(opts.headers).forEach(([key, value]) => {
                if (value) {
                    butlerHeaders.set(key, value);
                }
                else {
                    butlerHeaders.delete(key);
                }
            });
        }
        const response = await this.fetch(this.getApiUrl(path), {
            method: opts.method,
            headers: butlerHeaders,
            body: formatBody(opts.body),
            credentials: this.credentials,
        });
        return response;
    }
    async requestJson(path, opts) {
        const response = await this.request(path, opts);
        return await parseResponseJSON(response);
    }
    async get(path, opts) {
        return await this.requestJson(path, { ...opts, method: "GET" });
    }
    async post(path, opts) {
        return await this.requestJson(path, { ...opts, method: "POST" });
    }
    async put(path, opts) {
        return await this.requestJson(path, { ...opts, method: "PUT" });
    }
    async patch(path, opts) {
        return await this.requestJson(path, { ...opts, method: "PATCH" });
    }
    async delete(path, opts) {
        return await this.requestJson(path, { ...opts, method: "DELETE" });
    }
    async postRaw(path, opts) {
        return await this.request(path, { ...opts, method: "POST" });
    }
}
async function parseResponseJSON(response) {
    if (response.status === 204 || response.status === 205) {
        return null;
    }
    else if (response.status === 401) {
        throw new ApiError("Login token expired. Please log in to GitButler again.", response);
    }
    else if (response.status >= 400) {
        const text = await response.text();
        if (text.includes("401 Unauthorized") || text.includes("401 unauthorized")) {
            throw new ApiError("Login token expired. Please log in to GitButler again.", response);
        }
        throw new ApiError(`HTTP Error ${response.statusText}: ${text}`, response);
    }
    else {
        return await response.json();
    }
}
function formatBody(body) {
    if (!body)
        return;
    return body instanceof FormData ? body : JSON.stringify(body);
}
